            super().__init__(data)
            self.formatter = formatter
            try:
                self.format('', '')
            except KeyError as e:
                raise ValueError(f"Unknown template substitute: {e}")

def format(self, path, path_noext):
            return self.formatter.format(self.data, path=path, path_noext=path_noext)

